mapper.select:
SELECT 
FROM article

    is_deleted = 0
    AND article_title LIKE CONCAT('%', #{article.articleTitle}, '%')
    AND category_id = #{article.categoryId}
    AND author_id = #{article.authorId}
    AND status = #{article.status}

ORDER BY create_time DESC

SELECT COUNT(*)
FROM article

    is_deleted = 0
    AND article_title LIKE CONCAT('%', #{article.articleTitle}, '%')
    AND category_id = #{article.categoryId}
    AND author_id = #{article.authorId}
    AND status = #{article.status}

SELECT id, article_title, create_time, category_id
FROM article
WHERE is_deleted = 0 AND status = #{status}

    AND YEAR(create_time) = #{year}


    AND MONTH(create_time) = #{month}

ORDER BY create_time DESC
